const body = $json.body ?? $json;

const salesOrderId =
  body.salesOrderId ??
  body.salesOrderID ??
  body.id ??
  body.orderId ??
  body.data?.salesOrderId ??
  body.data?.id ??
  '';

if (!salesOrderId) {
  throw new Error('Sales Order ID was not found in webhook payload.');
}

return [
  {
    json: {
      salesOrderId: String(salesOrderId)
    }
  }
];

const output = [];

for (let sourceIndex = 0; sourceIndex < items.length; sourceIndex++) {
  const orderRaw = items[sourceIndex].json ?? {};
  const order = orderRaw.data && !Array.isArray(orderRaw.data) ? orderRaw.data : orderRaw;

  const salesOrderId =
    order.id ??
    order.salesOrderId ??
    order.orderId ??
    $('Prepare Sales Order ID').first().json.salesOrderId ??
    '';

  const salesOrderNumber =
    order.orderNumber ??
    order.number ??
    order.salesOrderNumber ??
    salesOrderId;

  const customerName =
    order.customer?.name ??
    order.customerName ??
    order.account?.name ??
    order.accountName ??
    '';

  let lines =
    order.lineItems ??
    order.lines ??
    order.items ??
    order.salesOrderItems ??
    order.salesOrderLines ??
    order.orderLines ??
    order.details ??
    [];

  if (lines && !Array.isArray(lines) && Array.isArray(lines.data)) {
    lines = lines.data;
  }

  if (!Array.isArray(lines) || lines.length === 0) {
    throw new Error(`No sales-order lines found for order ${salesOrderNumber}`);
  }

  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
    const line = lines[lineIndex];

    const itemId =
      line.item?.id ??
      line.itemId ??
      line.inventoryItemId ??
      line.product?.id ??
      line.productId ??
      '';

    const itemName =
      line.item?.name ??
      line.itemName ??
      line.product?.name ??
      line.productName ??
      line.name ??
      line.description ??
      `Line ${lineIndex + 1}`;

    const itemCode =
      line.item?.code ??
      line.itemCode ??
      line.sku ??
      line.itemSku ??
      line.productCode ??
      '';

    const itemDescription =
      line.item?.description ??
      line.itemDescription ??
      line.productDescription ??
      line.description ??
      '';

    const unitOfMeasure =
      line.unitOfMeasure ??
      line.uom ??
      line.unit ??
      '';

    const orderedQuantity = Number(
      line.quantity ??
      line.qty ??
      line.Quantity ??
      line.Qty ??
      0
    );

    if (!itemId) {
      throw new Error(`Missing item ID in order ${salesOrderNumber}, line ${lineIndex + 1}`);
    }

    if (!Number.isFinite(orderedQuantity) || orderedQuantity <= 0) {
      throw new Error(`Invalid quantity in order ${salesOrderNumber}, line ${lineIndex + 1}`);
    }

    output.push({
      json: {
        salesOrderId: String(salesOrderId),
        salesOrderNumber: String(salesOrderNumber),
        customerName: String(customerName),
        lineNumber: lineIndex + 1,
        itemId: String(itemId),
        itemName: String(itemName),
        itemCode: String(itemCode),
        itemDescription: String(itemDescription),
        unitOfMeasure: String(unitOfMeasure),
        orderedQuantity
      }
    });
  }
}

return output;

