parameters.jsCode:
const line = $('Loop Order Lines1').item.json ?? {};
const rawPreviousPO = $('Get Previous PO Detail').item.json ?? {};
const previousPO = rawPreviousPO.data && !Array.isArray(rawPreviousPO.data) ? rawPreviousPO.data : rawPreviousPO;
const contact = $input.first().json ?? {};

const vendor =
  previousPO.vendor ??
  previousPO.vendorAccount ??
  previousPO.account ??
  previousPO.supplier ??
  {};

const vendorId =
  vendor.id ??
  previousPO.vendorId ??
  previousPO.vendorAccountId ??
  previousPO.accountId ??
  previousPO.supplierId ??
  '';

const vendorName =
  vendor.name ??
  previousPO.vendorName ??
  previousPO.vendorAccountName ??
  previousPO.accountName ??
  previousPO.supplierName ??
  '';

if (!vendorId) {
  throw new Error(`Vendor ID was not found on the previous purchase order for item ${line.itemName}.`);
}

const emails = Array.isArray(contact.emails)
  ? contact.emails.filter((email) => email.active !== false)
  : [];

const selectedEmail =
  emails.find((email) => email.isPrimary === true) ??
  emails[0] ??
  {};

const vendorEmail = String(
  selectedEmail.email ??
  selectedEmail.emailAddress ??
  contact.email ??
  contact.emailAddress ??
  contact.primaryEmail ??
  ''
).trim();

if (!vendorEmail) {
  throw new Error(`No email address was found for vendor ${vendorName || vendorId}.`);
}

const vendorContactId =
  contact.id ??
  contact.contactId ??
  contact.accountContactId ??
  null;

const vendorContactName =
  [contact.firstName, contact.lastName]
    .filter(Boolean)
    .join(' ')
    .trim() ||
  contact.name ||
  vendorName ||
  'Vendor';

const previousLines =
  previousPO.lineItems ??
  previousPO.lines ??
  previousPO.items ??
  previousPO.purchaseOrderItems ??
  previousPO.purchaseOrderLines ??
  [];

const lineArray = Array.isArray(previousLines)
  ? previousLines
  : (Array.isArray(previousLines?.data) ? previousLines.data : []);

const previousLine =
  lineArray.find((poLine) => {
    const poItemId =
      poLine.item?.id ??
      poLine.itemId ??
      poLine.inventoryItemId ??
      poLine.product?.id ??
      poLine.productId ??
      '';

    return String(poItemId) === String(line.itemId);
  }) ??
  {};

const previousUnitPrice = Number(
  previousLine.unitPrice ??
  previousLine.price ??
  previousLine.cost ??
  previousLine.unitCost ??
  previousLine.rate ??
  0
);

return [{
  json: {
    ...line,
    vendorId: String(vendorId),
    vendorName: String(vendorName),
    vendorEmail,
    vendorContactId,
    vendorContactName,
    previousUnitPrice: Number.isFinite(previousUnitPrice) ? previousUnitPrice : 0,
    purchaseOrderTypeId:
      previousPO.purchaseOrderType?.id ??
      previousPO.purchaseOrderTypeId ??
      previousPO.poType?.id ??
      previousPO.poTypeId ??
      null,
    paymentTermId:
      previousPO.paymentTerm?.id ??
      previousPO.paymentTerms?.id ??
      previousPO.paymentTermId ??
      previousPO.paymentTermsId ??
      null,
    shippingMethodId:
      previousPO.shippingMethod?.id ??
      previousPO.shippingMethodId ??
      previousPO.shipVia?.id ??
      previousPO.shipViaId ??
      null,
    shipToAddressId:
      previousPO.shipToAddress?.id ??
      previousPO.shipToAddressId ??
      previousPO.deliveryAddress?.id ??
      previousPO.deliveryAddressId ??
      null,
    requestedById:
      previousPO.requestedBy?.id ??
      previousPO.requestedById ??
      null,
    currencyId:
      previousPO.currency?.id ??
      previousPO.currencyId ??
      null
  }
}];

const row = $input.first().json ?? {};
const rawPreviousPO = $('Get Previous PO Detail').item.json ?? {};
const previousPO = rawPreviousPO.data && !Array.isArray(rawPreviousPO.data) ? rawPreviousPO.data : rawPreviousPO;

const clone = (value) => JSON.parse(JSON.stringify(value));
const poPayload = clone(previousPO);

const previousPOType =
  previousPO.type ??
  previousPO.poType ??
  previousPO.purchaseOrderType ??
  null;

const previousPOTypeId = Number(
  previousPOType?.id ??
  previousPO.typeId ??
  previousPO.poTypeId ??
  previousPO.purchaseOrderTypeId ??
  0
);

if (!previousPOType || !Number.isFinite(previousPOTypeId) || previousPOTypeId <= 0) {
  throw new Error(`The previous PO does not contain a valid PO Type. Available previous PO fields: ${Object.keys(previousPO).join(', ')}`);
}

poPayload.type = clone(previousPOType);
poPayload.poType = clone(previousPOType);
poPayload.purchaseOrderType = clone(previousPOType);
poPayload.typeId = previousPOTypeId;
poPayload.poTypeId = previousPOTypeId;
poPayload.purchaseOrderTypeId = previousPOTypeId;

const previousVendor =
  previousPO.vendor ??
  previousPO.vendorAccount ??
  previousPO.account ??
  previousPO.supplier ??
  null;

const vendorId = Number(
  previousVendor?.id ??
  previousPO.vendorId ??
  previousPO.vendorAccountId ??
  previousPO.accountId ??
  previousPO.supplierId ??
  row.vendorId ??
  0
);

if (!previousVendor || !Number.isFinite(vendorId) || vendorId <= 0) {
  throw new Error('The previous PO does not contain a valid Vendor.');
}

poPayload.vendor = clone(previousVendor);

if (row.vendorContactId) {
  poPayload.vendorContactId = Number(row.vendorContactId);
}

poPayload.id = 0;
delete poPayload.purchaseOrderId;
delete poPayload.poId;
delete poPayload.purchaseOrderNumber;
delete poPayload.poNumber;
delete poPayload.number;
delete poPayload.dateCreated;
delete poPayload.createdDate;
delete poPayload.createdBy;
delete poPayload.lastUpdatedDate;
delete poPayload.lastUpdatedBy;
delete poPayload.total;
delete poPayload.subtotal;
delete poPayload.subTotal;
delete poPayload.taxTotal;
delete poPayload.balance;

const now = new Date();
const promiseDate = new Date(now);
promiseDate.setUTCDate(promiseDate.getUTCDate() + 7);

poPayload.purchaseOrderDate = now.toISOString();
poPayload.promiseDate = promiseDate.toISOString();

const lineKey = [
  'lineItems',
  'purchaseOrderLineItems',
  'purchaseOrderItems',
  'purchaseOrderLines',
  'lines',
  'items'
].find((key) => Array.isArray(previousPO[key]) || Array.isArray(previousPO[key]?.data));

if (!lineKey) {
  throw new Error('The previous PO line-item field could not be identified.');
}

const previousLines = Array.isArray(previousPO[lineKey])
  ? previousPO[lineKey]
  : previousPO[lineKey].data;

const itemId = Number(row.itemId);
const quantity = Number(row.orderedQuantity);

if (!Number.isFinite(itemId) || itemId <= 0) {
  throw new Error('Invalid item ID.');
}

if (!Number.isFinite(quantity) || quantity <= 0) {
  throw new Error('Invalid ordered quantity.');
}

const previousLine =
  previousLines.find((line) => {
    const previousItemId = Number(
      line.item?.id ??
      line.itemId ??
      line.inventoryItemId ??
      line.product?.id ??
      line.productId ??
      0
    );

    return previousItemId === itemId;
  }) ?? previousLines[0];

if (!previousLine) {
  throw new Error('No usable line item was found on the previous PO.');
}

const newLine = clone(previousLine);
newLine.id = 0;
delete newLine.purchaseOrderLineItemId;
delete newLine.purchaseOrderId;
delete newLine.quantityReceived;
delete newLine.quantityBilled;
delete newLine.amountReceived;
delete newLine.amountBilled;

newLine.item = {
  ...(newLine.item ?? {}),
  id: itemId,
  name: String(row.itemName ?? '')
};

newLine.itemId = itemId;
newLine.quantity = quantity;

if ('qty' in newLine) {
  newLine.qty = quantity;
}

if ('orderedQuantity' in newLine) {
  newLine.orderedQuantity = quantity;
}

const previousUnitPrice = Number(
  row.previousUnitPrice ??
  newLine.unitPrice ??
  newLine.price ??
  newLine.unitCost ??
  newLine.cost ??
  newLine.rate ??
  0
);

if ('unitPrice' in newLine) {
  newLine.unitPrice = previousUnitPrice;
} else if ('price' in newLine) {
  newLine.price = previousUnitPrice;
} else if ('unitCost' in newLine) {
  newLine.unitCost = previousUnitPrice;
} else {
  newLine.unitPrice = previousUnitPrice;
}

if (newLine.status) {
  newLine.status = {
    ...newLine.status,
    id: 113,
    name: 'Pending'
  };
}

if ('statusId' in newLine) {
  newLine.statusId = 113;
}

poPayload[lineKey] = [newLine];

if (poPayload.status) {
  poPayload.status = {
    ...poPayload.status,
    id: 109,
    name: 'In Progress'
  };
}

if ('statusId' in poPayload) {
  poPayload.statusId = 109;
}

// Link the new PO to the CURRENT sales order and drop-ship to the CURRENT customer.
const soRaw2 = $('Get Sales Order Detail').first().json ?? {};
const so2 = soRaw2.data && !Array.isArray(soRaw2.data) ? soRaw2.data : soRaw2;
const soCustomer = so2.customer ?? null;
if (soCustomer && 'dropShipCustomer' in poPayload) poPayload.dropShipCustomer = clone(soCustomer);
if (soCustomer?.id && 'dropShipCustomerId' in poPayload) poPayload.dropShipCustomerId = Number(soCustomer.id);
poPayload.title = 'Auto PO for SO ' + String(row.salesOrderNumber ?? '');
if ('memo' in poPayload) poPayload.memo = 'Auto-created from Sales Order ' + String(row.salesOrderNumber ?? '');
// Previous order's custom fields must never leak onto the new PO.
delete poPayload.customFields;

return [
  {
    json: {
      ...row,
      poPayload
    }
  }
];

