// Checkpoint poller: remembers the highest SO id it has seen and emits
// ONE new sales order per run (oldest unseen first). First run only
// baselines the checkpoint so ancient orders are never reprocessed.
const sd = $getWorkflowStaticData('global');
const rows = ($json.data ?? []).map((r) => Number(r.id)).filter((n) => Number.isFinite(n) && n > 0);
if (!rows.length) return [];
const maxId = Math.max(...rows);
const last = Number(sd.lastSoId ?? 0);
if (!last) { sd.lastSoId = maxId; return []; }
const fresh = rows.filter((n) => n > last).sort((a, b) => a - b);
if (!fresh.length) return [];
sd.lastSoId = fresh[0];
return [{ json: { salesOrderId: String(fresh[0]) } }];

// Idempotency: one SO -> one automation run, ever. Webhook + poller both pass through here.
const sd = $getWorkflowStaticData('global');
if (!Array.isArray(sd.processedSoIds)) sd.processedSoIds = [];
const id = String($json.salesOrderId ?? '');
if (!id) return [];
if (sd.processedSoIds.includes(id)) return [];
sd.processedSoIds.push(id);
if (sd.processedSoIds.length > 500) sd.processedSoIds = sd.processedSoIds.slice(-500);
return [{ json: { salesOrderId: id } }];
